  ('e3488694-877f-5251-957c-012c5861bd48', 'Tirana', 'assets/cities/tirana.jpg', 'assets/cities/tirana.jpg', 'Tirana, Albania', 41.3275, 19.8187, 'Albania''s lively capital with cafes, culture, nightlife and city escapes.', true),
